arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// ── ML.NET setup ───────────────────────────────────────────────────
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Train / test split (80 / 20)
var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

// Pipeline: encode Region, concatenate features, train with LightGBM-style FastTree
var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree(
        labelColumnName: "Label", featureColumnName: "Features"));

Console.WriteLine("Training churn model …");
var model = pipeline.Fit(split.TrainSet);

// Evaluate
var metrics = mlContext.BinaryClassification.Evaluate(
    model.Transform(split.TestSet), labelColumnName: "Label");
Console.WriteLine($"Accuracy : {metrics.Accuracy:P2}");
Console.WriteLine($"AUC      : {metrics.AreaUnderRocCurve:P2}");
Console.WriteLine($"F1 Score : {metrics.F1Score:P2}");

// Create a reusable prediction engine
var predictor = mlContext.Model
    .CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// ── API endpoints ──────────────────────────────────────────────────
app.MapGet("/", () => "Churn Predictor API – POST /predict with customer JSON");

app.MapPost("/predict", (CustomerInput input) =>
{
    var customerData = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };

    var result = predictor.Predict(customerData);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Confidence = result.Probability
    });
});

app.Run();

// ── Data models ────────────────────────────────────────────────────
public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")]
    [BooleanType]
    public bool Churned { get; set; }
}

// Custom type mapping: "Yes"/"No" → bool
[AttributeUsage(AttributeTargets.Property)]
public class BooleanTypeAttribute : Attribute { }

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

